import React, { useState, useEffect } from 'react';
import { getTasks, createTask, toggleTask, deleteTask } from './api';

function App() {
  const [tasks, setTasks] = useState([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isAdding, setIsAdding] = useState(false);

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await getTasks();
      setTasks(data);
    } catch (err) {
      setError(err.message || 'Failed to load tasks.');
    } finally {
      setLoading(false);
    }
  };

  const handleAddTask = async (e) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;

    try {
      setIsAdding(true);
      setError(null);
      const newTask = await createTask(newTaskTitle);
      setTasks([...tasks, newTask]);
      setNewTaskTitle('');
    } catch (err) {
      setError(err.message || 'Failed to add task.');
    } finally {
      setIsAdding(false);
    }
  };

  const handleToggleTask = async (id) => {
    // Optimistic update
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
    try {
      await toggleTask(id);
    } catch (err) {
      setError('Failed to update status.');
      // Revert optimism on fail
      setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
    }
  };

  const handleDeleteTask = async (id) => {
    if (!window.confirm('Are you sure you want to delete this task?')) return;

    // Optimistic update
    setTasks(tasks.filter(t => t.id !== id));
    try {
      await deleteTask(id);
    } catch (err) {
      setError('Failed to delete task.');
      // Full refetch on fail from optimism
      fetchTasks();
    }
  };

  return (
    <div style={{ maxWidth: '600px', margin: '2rem auto', padding: '0 1rem', fontFamily: 'sans-serif' }}>
      <div style={{ backgroundColor: '#fff', borderRadius: '8px', padding: '2rem', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <h1 style={{ textAlign: 'center', marginBottom: '1.5rem', color: '#1f2937' }}>Task Manager</h1>

        {error && (
          <div style={{ backgroundColor: '#fee2e2', color: '#b91c1c', padding: '0.75rem', borderRadius: '4px', marginBottom: '1rem', fontSize: '0.875rem' }}>
            {error}
          </div>
        )}

        <form onSubmit={handleAddTask} style={{ display: 'flex', gap: '0.5rem', marginBottom: '2rem' }}>
          <input
            type="text"
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="What needs to be done?"
            disabled={isAdding}
            style={{ flexGrow: 1, padding: '0.75rem 1rem', borderRadius: '4px', border: '1px solid #d1d5db', fontSize: '1rem', outline: 'none' }}
          />
          <button 
            type="submit" 
            disabled={isAdding || !newTaskTitle.trim()}
            style={{ 
              padding: '0 1.5rem', 
              backgroundColor: !newTaskTitle.trim() ? '#9ca3af' : '#4f46e5', 
              color: 'white', 
              border: 'none', 
              borderRadius: '4px', 
              cursor: !newTaskTitle.trim() ? 'not-allowed' : 'pointer', 
              fontSize: '1rem',
              fontWeight: '500',
              transition: 'background-color 0.2s'
            }}
          >
            {isAdding ? 'Adding...' : 'Add Task'}
          </button>
        </form>

        {loading ? (
          <p style={{ textAlign: 'center', color: '#6b7280' }}>Loading tasks...</p>
        ) : (
          <div>
            {tasks.length === 0 ? (
              <p style={{ textAlign: 'center', color: '#6b7280', fontStyle: 'italic' }}>No tasks yet. Add one above!</p>
            ) : (
              <ul style={{ listStyle: 'none', padding: 0, display: 'flex', flexDirection: 'column', gap: '0.75rem', margin: 0 }}>
                {tasks.map(task => (
                  <li 
                    key={task.id} 
                    style={{ 
                      display: 'flex', 
                      alignItems: 'center', 
                      justifyContent: 'space-between', 
                      padding: '1rem',
                      border: '1px solid #e5e7eb',
                      borderRadius: '4px',
                      backgroundColor: '#f9fafb',
                      transition: 'border-color 0.2s'
                    }}
                  >
                    <div 
                      onClick={() => handleToggleTask(task.id)}
                      style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', cursor: 'pointer', flexGrow: 1 }}
                    >
                      <input 
                        type="checkbox" 
                        checked={task.completed} 
                        readOnly
                        style={{ width: '1.25rem', height: '1.25rem', cursor: 'pointer', accentColor: '#4f46e5' }}
                      />
                      <span style={{ 
                        textDecoration: task.completed ? 'line-through' : 'none',
                        color: task.completed ? '#9ca3af' : '#1f2937',
                        fontSize: '1rem',
                        wordBreak: 'break-word',
                        transition: 'color 0.2s'
                      }}>
                        {task.title}
                      </span>
                    </div>
                    <button 
                      onClick={() => handleDeleteTask(task.id)}
                      style={{ 
                        background: 'none', 
                        border: 'none', 
                        color: '#ef4444', 
                        cursor: 'pointer', 
                        padding: '0.25rem',
                        fontSize: '0.875rem',
                        fontWeight: '500'
                      }}
                      aria-label="Delete task"
                    >
                      Delete
                    </button>
                  </li>
                ))}
              </ul>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
